public void testBackwardsInferenceNewWithMultipleArgs() {
    inFunction(
        "/**\n" +
        " * @constructor\n" +
        " * @param {{bar: string}} a\n" +
        " * @param {{baz: boolean}} b\n" +
        " */" +
        "function G(a, b) {}" +
        "var x = {};" +
        "var z = {};" +
        "new G(x, z);");

    assertEquals("{bar: string}", getType("x").toString());
    assertEquals("{baz: boolean}", getType("z").toString());
  }

public void testBackwardsInferenceNewWithNestedObject() {
    inFunction(
        "/**\n" +
        " * @constructor\n" +
        " * @param {{nested: {inner: number}}} x\n" +
        " */" +
        "function H(x) {}" +
        "var obj = {};" +
        "new H(obj);");

    assertEquals("{nested: {inner: number}}", getType("obj").toString());
  }
